<span class="line"><span class="token class-name"><span class="token keyword">string</span></span> trimEnd <span class="token operator">=</span> str<span class="token punctuation">.</span><span class="token function">TrimEnd</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>          <span class="token comment">// 去除结尾空格</span></span>
